129→function seedStoreLoaded(points: number) {
130→  const state = useRootStore.getState() as Record<string, any>;
131→  if (state.pointsExtractActions) {
132→    state.pointsExtractActions.setBalance(points);
133→    state.pointsExtractActions.setExtractData(MOCK_EXTRACT_DATA);
134→  }
135→}
136→
137→function seedStoreLoading() {
138→  const state = useRootStore.getState() as Record<string, any>;
139→  if (state.pointsExtractActions) {
140→    state.pointsExtractActions.setExtractStatus(PointsExtractStatus.LOADING);
141→    state.pointsExtractActions.setBalanceStatus(PointsBalanceStatus.LOADING);
142→  }
143→}
144→
145→function seedStoreError() {
146→  const state = useRootStore.getState() as Record<string, any>;
147→  if (state.pointsExtractActions) {
148→    state.pointsExtractActions.setExtractStatus(PointsExtractStatus.ERROR);
149→    state.pointsExtractActions.setBalance(0);
150→  }
151→}
152→
153→function seedStoreEmpty(points: number) {
154→  const state = useRootStore.getState() as Record<string, any>;
155→  if (state.pointsExtractActions) {
156→    state.pointsExtractActions.setBalance(points);
157→    state.pointsExtractActions.setExtractData({
158→      transactions: [],
159→      pagination: { page: 1, pageSize: 20, total: 0, totalPages: 0 },
160→    });
161→  }
162→}
