207→        Algo deu errado!
208→      </Text>
209→      <Text
210→        type="paragraphMD"
211→        align="center"
212→        color="INTENSE_COLOR_05"
213→        mb="smaller"
214→      >
215→        Por favor, tente de novo.
216→      </Text>
217→    </Box>
218→  );
219→}
