221→function ExtractStoryWrapper({
222→  points = 15320,
223→  isLoading = false,
224→  hasError = false,
225→  isEmpty = false,
226→}: {
227→  points?: number;
228→  isLoading?: boolean;
229→  hasError?: boolean;
230→  isEmpty?: boolean;
231→}) {
232→  const [transactionsData, setTransactionsData] = React.useState<
233→    propsItemsListCardTransition[]
234→  >([]);
235→
236→  useEffect(() => {
237→    if (hasError) {
238→      seedStoreError();
239→      return;
240→    }
241→    if (isLoading) {
242→      seedStoreLoading();
243→      return;
244→    }
245→    if (isEmpty) {
246→      seedStoreEmpty(points);
247→      return;
248→    }
249→    seedStoreLoaded(points);
250→  }, [points, isLoading, hasError, isEmpty]);
251→
252→  useEffect(() => {
253→    if (!isLoading && !hasError && !isEmpty) {
254→      const processed = processPointsExtractData(MOCK_EXTRACT_DATA);
255→      setTransactionsData(processed.mappedTransactions);
256→    } else if (isEmpty) {
257→      setTransactionsData([]);
258→    }
259→  }, [isLoading, hasError, isEmpty]);
260→
261→  if (hasError) {
262→    return (
263→      <Box bgColor="BRAND_COMPLEMENT_03" flex={1}>
264→        <Header
265→          title="Extrato"
266→          iconLeft="icon-back"
267→          hideLeftIcon={false}
268→          onBack={() => {}}
269→        />
270→        <ErrorState onRetry={() => {}} />
271→      </Box>
272→    );
273→  }
274→
275→  const showTransactionsList = isLoading || transactionsData.length > 0;
276→
277→  return (
278→    <Box bgColor="BRAND_COMPLEMENT_03" flex={1}>
279→      <Header
280→        title="Extrato"
281→        iconLeft="icon-back"
282→        hideLeftIcon={false}
283→        onBack={() => {}}
284→      />
285→      <ScrollView contentContainerStyle={{ flexGrow: 1 }}>
286→        <Box ml="smaller" mr="smaller" mt="smaller" mb="xxxs">
287→          <CardPoints
288→            icon="icon-benefits"
289→            iconInfo="icon-help"
290→            title="Pontos disponíveis"
291→            valuePoints={
292→              isLoading
293→                ? ''
294→                : Math.floor(points).toLocaleString('pt-br')
295→            }
296→            hideBottom
297→            isLoading={isLoading}
298→            onPressIconInfo={() => {}}
299→          />
300→
301→          <Text
302→            type="paragraphXXXL"
303→            mb="xxxxs"
304→            mt="xxs"
305→            color="INTENSE_COLOR_05"
306→          >
307→            Lançamentos
308→          </Text>
309→
310→          <SeparatorHorizontal
311→            borderWidth="smaller"
312→            borderColor="BRAND_COMPLEMENT_02"
313→            height={1}
314→            mb="xxxxs"
315→            width="100%"
316→          />
317→          <SearchUsed
318→            placeholder="Buscar por pontos, tipos de compra etc"
319→            onChangeText={() => {}}
320→            value=""
321→            showIcon={false}
322→            firstIcon={undefined}
323→            onPressIn={() => {}}
324→            numberIcon={undefined}
325→            secondIcon="icon-filter-settings"
326→            secondOnPress={() => {}}
327→            showFilter
328→          />
329→        </Box>
330→
331→        <Box
332→          ml={isLoading ? 'xs' : 'none'}
333→          mr={isLoading ? 'xs' : 'none'}
334→        >
335→          {showTransactionsList ? (
336→            <Tabs
337→              items={[
338→                {
339→                  id: 0,
340→                  title: 'Todos',
341→                  component: (
342→                    <TransactionsList
343→                      items={transactionsData}
344→                      isLoading={isLoading}
345→                    />
346→                  ),
347→                },
348→                {
349→                  id: 1,
350→                  title: 'A expirar',
351→                  component: <></>,
352→                },
353→              ]}
354→              showBackground={false}
355→              hasScroll={false}
356→              loadingType="light"
357→              onChange={() => {}}
358→              type="options"
359→              isLoading={isLoading}
360→            />
361→          ) : (
362→            <>
363→              <Box direction="row" ml="smaller" mb="xxxxs">
364→                <Box mr="xs" style={{ borderBottomWidth: 2, borderBottomColor: '#E91E63', paddingBottom: 8 }}>
365→                  <Text type="subtitleXXL" color="INTENSE_COLOR_05">Todos</Text>
366→                </Box>
367→                <Box style={{ paddingBottom: 8 }}>
368→                  <Text type="paragraphMD" color="INTENSE_COLOR_03">A expirar</Text>
369→                </Box>
370→              </Box>
371→              <SeparatorHorizontal
372→                width="100%"
373→                height={1}
374→                borderColor="BRAND_COMPLEMENT_02"
375→              />
376→              <EmptyList
377→                label={
378→                  isEmpty
379→                    ? 'Para ganhar pontos, use seu cartão Sem Parar Mais ou a Tag.'
380→                    : 'Não encontramos resultados para sua busca.'
381→                }
382→              />
383→            </>
384→          )}
385→        </Box>
386→      </ScrollView>
387→    </Box>
388→  );
389→}
